
// ── SLIDE ENGINE ──
const slider = document.getElementById('slider');

const slides = document.querySelectorAll('.slide');
const totalSlides = slides.length;
let currentSlide = 0;
let scrollRaf = null;

const heroTitle = document.querySelector('#slide-0 .hero-title');
const heroRipple = document.querySelector('#slide-0 .hero-ripple');
const scrollVideoSlide = document.getElementById('slide-video');
const scrollSyncVideo = document.getElementById('scroll-sync-video');
const videoGrowText = document.querySelector('#slide-video .video-grow-text');
const videoWordYou = document.querySelector('#slide-video .video-word-you');
const videoWordTurn = document.querySelector('#slide-video .video-word-turn');
const videoSlideIndex = scrollVideoSlide ? Array.from(slides).indexOf(scrollVideoSlide) : -1;
const flashSlide = document.getElementById('slide-flash');
const flashCaption = document.querySelector('#slide-flash .flash-caption');
const flashSlideIndex = flashSlide ? Array.from(slides).indexOf(flashSlide) : -1;
const workbookSlide = document.getElementById('slide-5');
const workbookRail = document.querySelector('#slide-5 .card-grid.six');
const reflectionBgSlideIds = new Set(['slide-1', 'slide-2', 'slide-3', 'slide-4', 'slide-5', 'slide-6']);
const clamp = (value, min, max) => Math.min(max, Math.max(min, value));
const videoLockKeys = new Set(['ArrowDown', 'ArrowUp', 'ArrowLeft', 'ArrowRight', 'PageDown', 'PageUp', 'Home', 'End', ' ']);
const videoScrollStepSeconds = 1.6;
const flashMaxSteps = 6;
const flashCaptionTexts = {
  1: '이제부터 나를 돌아보는 거야',
  3: '준비됐어?',
  5: '내 손을 잡아'
};
let videoLocked = false;
let flashLocked = false;
let lockedScrollTop = 0;
let lastScrollTop = 0;
let lastScrollDirection = 1;
let lastVideoStepAt = 0;
let lastFlashStepAt = 0;
let lastWorkbookWheelAt = 0;
let workbookRailAnimation = null;
let workbookRailTarget = 0;
let workbookWasActive = false;
let videoExitUntil = 0;
let flashExitUntil = 0;
let flashStep = 0;
let videoAutoExiting = false;
let videoAutoExitTimer = null;
let flashAutoExiting = false;
let flashAutoExitTimer = null;
let touchStartY = 0;

// Dots 생성
const dotsEl = document.getElementById('slide-dots');
slides.forEach((_, i) => {
  const d = document.createElement('div');
  d.className = 's-dot' + (i === 0 ? ' active' : '');
  d.addEventListener('click', () => goTo(i));
  dotsEl.appendChild(d);
});

document.getElementById('total-slides').textContent = String(totalSlides).padStart(2,'0');

function goTo(n) {
  n = Math.max(0, Math.min(totalSlides - 1, n));
  if (videoLocked && n !== videoSlideIndex) return;
  if (flashLocked && n !== flashSlideIndex) return;
  currentSlide = n;
  slider.scrollTo({ top: slides[n].offsetTop, behavior: 'smooth' });
  updateNav();
}

function updateProgressFromScroll() {
  const maxScroll = slider.scrollHeight - slider.clientHeight;
  const pct = maxScroll > 0 ? (slider.scrollTop / maxScroll) * 100 : 0;
  document.getElementById('progress-fill').style.width = pct + '%';
}

function updateNav() {
  document.getElementById('cur-slide').textContent = String(currentSlide + 1).padStart(2,'0');
  document.querySelectorAll('.s-dot').forEach((d,i) => d.classList.toggle('active', i === currentSlide));
  document.querySelectorAll('.nav-ch').forEach((b,i) => b.classList.toggle('active', i === currentSlide));
  const activeSlide = slides[currentSlide];
  document.body.classList.toggle('reflection-bg-visible', !!activeSlide && reflectionBgSlideIds.has(activeSlide.id));
  updateProgressFromScroll();
}

function updateFlashFrame(pulse = true) {
  if (!flashSlide) return;
  const showFinal = flashStep >= flashMaxSteps;
  flashSlide.classList.toggle('show-final', showFinal);
  flashSlide.classList.toggle('show-alt', !showFinal && Math.abs(flashStep) % 2 === 1);
  if (flashCaption) {
    const captionText = flashCaptionTexts[flashStep] || '';
    flashCaption.textContent = captionText;
    flashCaption.classList.toggle('is-active', !!captionText);
  }
  if (!pulse) return;
  flashSlide.classList.remove('flash-pulse');
  void flashSlide.offsetWidth;
  flashSlide.classList.add('flash-pulse');
}

function setFlashFade(opacity) {
  flashSlide?.style.setProperty('--flash-fade-opacity', String(opacity));
}

function revealFlashSection() {
  if (!flashSlide) return;
  setFlashFade(1);
  requestAnimationFrame(() => {
    requestAnimationFrame(() => setFlashFade(0));
  });
}

function lockFlashSection() {
  if (!flashSlide || flashLocked || performance.now() < flashExitUntil) return;

  flashLocked = true;
  flashAutoExiting = false;
  flashStep = lastScrollDirection < 0 ? flashMaxSteps : 0;
  lockedScrollTop = flashSlide.offsetTop;
  currentSlide = flashSlideIndex;
  updateNav();

  slider.scrollTo({ top: lockedScrollTop, behavior: 'auto' });
  slider.classList.add('flash-section-locked');
  flashSlide.classList.add('is-flash-active');
  updateFlashFrame(false);
  revealFlashSection();
}

function unlockFlashSection() {
  if (!flashLocked) return;
  if (flashAutoExitTimer) {
    clearTimeout(flashAutoExitTimer);
    flashAutoExitTimer = null;
  }
  flashLocked = false;
  flashAutoExiting = false;
  flashExitUntil = performance.now() + 900;
  slider.classList.remove('flash-section-locked');
  flashSlide?.classList.remove('is-flash-active', 'flash-pulse');
  updateScrollEffects();
}

function scheduleFlashExit() {
  if (flashAutoExiting) return;
  flashAutoExiting = true;
  flashAutoExitTimer = setTimeout(() => {
    setFlashFade(1);
    flashAutoExitTimer = setTimeout(() => {
      flashAutoExitTimer = null;
      flashAutoExiting = false;
      unlockFlashSection();
      goTo(flashSlideIndex + 1);
    }, 980);
  }, 420);
}

function scrubFlashBy(direction) {
  if (!flashLocked || !flashSlide || flashAutoExiting) return;

  if (direction > 0) {
    flashStep = Math.min(flashMaxSteps, flashStep + 1);
    updateFlashFrame(true);
    if (flashStep >= flashMaxSteps) scheduleFlashExit();
    return;
  }

  if (flashStep <= 0) {
    unlockFlashSection();
    goTo(flashSlideIndex - 1);
    return;
  }

  flashStep = Math.max(0, flashStep - 1);
  updateFlashFrame(true);
}

function setVideoWordCue(element, opacity, scale, x, y, blur, spacing) {
  if (!element) return;
  element.style.setProperty('--word-opacity', opacity.toFixed(3));
  element.style.setProperty('--word-scale', scale.toFixed(3));
  element.style.setProperty('--word-x', `${x.toFixed(2)}vw`);
  element.style.setProperty('--word-y', `${y.toFixed(2)}vh`);
  element.style.setProperty('--word-blur', `${blur.toFixed(2)}px`);
  element.style.setProperty('--word-spacing', `${spacing.toFixed(3)}em`);
}

function updateVideoTextCue() {
  if (!scrollVideoSlide || !scrollSyncVideo) return;

  const time = scrollSyncVideo.currentTime || 0;
  const duration = Number.isFinite(scrollSyncVideo.duration) && scrollSyncVideo.duration > 0 ? scrollSyncVideo.duration : 10;
  const videoProgress = clamp(time / duration, 0, 1);
  const videoBlur = 0.35 + videoProgress * 12;
  const compactVideo = window.matchMedia('(max-width: 900px)').matches;
  const videoScale = compactVideo ? 1 + videoProgress * 0.012 : 1.018 + videoProgress * 0.035;
  scrollVideoSlide.style.setProperty('--scroll-video-blur', `${videoBlur.toFixed(2)}px`);
  scrollVideoSlide.style.setProperty('--scroll-video-scale', videoScale.toFixed(3));

  const grow = clamp((time - 1) / 3, 0, 1);
  const appear = time >= 1 ? clamp(0.25 + (time - 1) / 0.45, 0, 1) : 0;
  const vanish = clamp((time - 3.85) / 0.15, 0, 1);
  const firstWordDrift = compactVideo ? 6 : 16;
  const firstWordVanishDrift = compactVideo ? 3 : 6;

  if (videoGrowText) {
    scrollVideoSlide.style.setProperty('--video-text-opacity', (appear * (1 - vanish)).toFixed(3));
    scrollVideoSlide.style.setProperty('--video-text-scale', (0.24 + grow * 0.44 + vanish * 0.14).toFixed(3));
    scrollVideoSlide.style.setProperty('--video-text-x', `${(-grow * firstWordDrift - vanish * firstWordVanishDrift).toFixed(2)}vw`);
    scrollVideoSlide.style.setProperty('--video-text-blur', `${(14 - appear * 14 + vanish * 18).toFixed(2)}px`);
    scrollVideoSlide.style.setProperty('--video-text-spacing', `${(0.18 - grow * 0.02 + vanish * 0.08).toFixed(3)}em`);
  }

  const youGrow = clamp((time - 3) / 3, 0, 1);
  const youAppear = time >= 3 ? clamp(0.25 + (time - 3) / 0.45, 0, 1) : 0;
  const youVanish = clamp((time - 5.85) / 0.15, 0, 1);
  const sideDrift = compactVideo ? 5 : 22;
  const upDrift = compactVideo ? 5 : 22;
  const downDrift = compactVideo ? 6 : 24;
  setVideoWordCue(
    videoWordYou,
    youAppear * (1 - youVanish),
    0.22 + youGrow * 0.78 + youVanish * 0.18,
    youGrow * sideDrift + youVanish * 4,
    -youGrow * upDrift - youVanish * 4,
    14 - youAppear * 14 + youVanish * 18,
    0.18 - youGrow * 0.04 + youVanish * 0.08
  );

  const turnGrow = clamp((time - 5) / 3, 0, 1);
  const turnAppear = time >= 5 ? clamp(0.25 + (time - 5) / 0.45, 0, 1) : 0;
  const turnVanish = clamp((time - 7.85) / 0.15, 0, 1);
  setVideoWordCue(
    videoWordTurn,
    turnAppear * (1 - turnVanish),
    0.22 + turnGrow * 0.9 + turnVanish * 0.18,
    0,
    turnGrow * downDrift + turnVanish * 4,
    14 - turnAppear * 14 + turnVanish * 18,
    0.18 - turnGrow * 0.04 + turnVanish * 0.08
  );
}

function setVideoFade(opacity) {
  scrollVideoSlide?.style.setProperty('--video-fade-opacity', String(opacity));
}

function revealVideoSection() {
  if (!scrollVideoSlide) return;
  setVideoFade(1);
  requestAnimationFrame(() => {
    requestAnimationFrame(() => setVideoFade(0));
  });
}

function lockVideoSection() {
  if (!scrollVideoSlide || !scrollSyncVideo || videoLocked || performance.now() < videoExitUntil) return;

  videoLocked = true;
  videoAutoExiting = false;
  lockedScrollTop = scrollVideoSlide.offsetTop;
  currentSlide = videoSlideIndex;
  updateNav();

  slider.scrollTo({ top: lockedScrollTop, behavior: 'auto' });
  slider.classList.add('video-section-locked');
  scrollVideoSlide.classList.add('is-playing');

  scrollSyncVideo.controls = false;
  scrollSyncVideo.muted = true;
  scrollSyncVideo.pause();
  try {
    const duration = scrollSyncVideo.duration;
    scrollSyncVideo.currentTime = lastScrollDirection < 0 && Number.isFinite(duration) ? Math.max(0, duration - 0.05) : 0;
  } catch (error) {
    // Metadata may still be loading on first entry.
  }
  updateVideoTextCue();
  revealVideoSection();
}

function unlockVideoSection() {
  if (!videoLocked) return;
  if (videoAutoExitTimer) {
    clearTimeout(videoAutoExitTimer);
    videoAutoExitTimer = null;
  }
  videoLocked = false;
  videoAutoExiting = false;
  videoExitUntil = performance.now() + 900;
  slider.classList.remove('video-section-locked');
  scrollVideoSlide?.classList.remove('is-playing');
  scrollSyncVideo?.pause();
  scrollVideoSlide?.style.setProperty('--video-text-opacity', '0');
  videoWordYou?.style.setProperty('--word-opacity', '0');
  videoWordTurn?.style.setProperty('--word-opacity', '0');
  updateScrollEffects();
}

function scheduleVideoExit(targetIndex) {
  if (videoAutoExiting) return;
  videoAutoExiting = true;
  setVideoFade(1);
  videoAutoExitTimer = setTimeout(() => {
    videoAutoExitTimer = null;
    videoAutoExiting = false;
    unlockVideoSection();
    goTo(targetIndex);
  }, 980);
}

function scrubVideoBy(direction) {
  if (!videoLocked || !scrollSyncVideo || videoAutoExiting) return;
  const duration = scrollSyncVideo.duration;
  if (!Number.isFinite(duration) || duration <= 0) return;

  const current = scrollSyncVideo.currentTime;
  const atStart = current <= 0.05;
  const atEnd = current >= duration - 0.08;

  if (direction > 0 && atEnd) {
    scheduleVideoExit(videoSlideIndex + 1);
    return;
  }

  if (direction < 0 && atStart) {
    scheduleVideoExit(videoSlideIndex - 1);
    return;
  }

  scrollSyncVideo.pause();
  scrollSyncVideo.currentTime = clamp(current + direction * videoScrollStepSeconds, 0, duration);
  updateVideoTextCue();
}

function holdVideoSection(event) {
  if (!videoLocked) return;
  if (event.cancelable) event.preventDefault();
  slider.scrollTop = lockedScrollTop;

  const now = performance.now();
  if (now - lastVideoStepAt < 360) return;

  const direction = event.deltaY > 0 ? 1 : -1;
  lastVideoStepAt = now;
  scrubVideoBy(direction);
}

function holdFlashSection(event) {
  if (!flashLocked) return;
  if (event.cancelable) event.preventDefault();
  slider.scrollTop = lockedScrollTop;
  if (flashAutoExiting || event.deltaY === 0) return;

  const now = performance.now();
  if (now - lastFlashStepAt < 360) return;

  lastFlashStepAt = now;
  scrubFlashBy(event.deltaY > 0 ? 1 : -1);
}

function handleVideoTouchStart(event) {
  touchStartY = event.touches?.[0]?.clientY || 0;
}

function holdVideoTouchMove(event) {
  if (!videoLocked) return;
  if (event.cancelable) event.preventDefault();

  const currentY = event.touches?.[0]?.clientY || touchStartY;
  const delta = touchStartY - currentY;
  if (Math.abs(delta) < 44) return;

  scrubVideoBy(delta > 0 ? 1 : -1);
  touchStartY = currentY;
}

function holdFlashTouchMove(event) {
  if (!flashLocked) return;
  if (event.cancelable) event.preventDefault();
  if (flashAutoExiting) return;

  const currentY = event.touches?.[0]?.clientY || touchStartY;
  const delta = touchStartY - currentY;
  if (Math.abs(delta) < 44) return;

  const now = performance.now();
  if (now - lastFlashStepAt < 360) return;

  lastFlashStepAt = now;
  scrubFlashBy(delta > 0 ? 1 : -1);
  touchStartY = currentY;
}

function handleSliderScroll() {
  if (!videoLocked && !flashLocked) {
    const nextScrollTop = slider.scrollTop;
    if (Math.abs(nextScrollTop - lastScrollTop) > 1) {
      lastScrollDirection = nextScrollTop > lastScrollTop ? 1 : -1;
      lastScrollTop = nextScrollTop;
    }
  }
  requestScrollTick();
}

// Scroll spy
const obs = new IntersectionObserver((entries) => {
  entries.forEach(e => {
    if (e.isIntersecting && e.intersectionRatio >= 0.35) {
      e.target.classList.add('is-visible');
      const idx = Array.from(slides).indexOf(e.target);
      if (idx !== -1) { currentSlide = idx; updateNav(); }
      if (e.target === scrollVideoSlide && e.intersectionRatio >= 0.35) {
        lockVideoSection();
      }
      if (e.target === flashSlide && e.intersectionRatio >= 0.55) {
        lockFlashSection();
      }
    }
  });
}, { root: slider, threshold: [0.2, 0.35, 0.55, 0.75] });
slides.forEach(s => obs.observe(s));
slides[0]?.classList.add('is-visible');

function updateScrollEffects() {
  scrollRaf = null;

  const viewport = Math.max(1, slider.clientHeight);
  if ((videoLocked || flashLocked) && Math.abs(slider.scrollTop - lockedScrollTop) > 1) {
    slider.scrollTop = lockedScrollTop;
  }

  const workbookActive = isWorkbookSlideActive();
  if (workbookRail && workbookActive && !workbookWasActive && lastScrollDirection > 0) {
    if (workbookRailAnimation) {
      cancelAnimationFrame(workbookRailAnimation);
      workbookRailAnimation = null;
    }
    workbookRailTarget = 0;
    workbookRail.scrollLeft = 0;
  }
  workbookWasActive = workbookActive;

  const heroProgress = clamp(slider.scrollTop / viewport, 0, 1);
  document.documentElement.style.setProperty('--hero-progress', heroProgress.toFixed(3));

  if (heroTitle) {
    heroTitle.style.opacity = String(clamp(1 - heroProgress * 1.55, 0, 1));
    heroTitle.style.transform = `translate3d(0, ${heroProgress * -26}px, 0)`;
  }

  if (heroRipple) {
    heroRipple.style.transform = `translate3d(0, ${heroProgress * -1.8}%, 0) scale(${1.03 + heroProgress * 0.16})`;
    heroRipple.style.filter = `blur(${4 + heroProgress * 18}px) brightness(${1.2 + heroProgress * 0.55}) saturate(1.2)`;
    heroRipple.style.opacity = String(0.14 + heroProgress * 0.32);
  }

  slides.forEach((slide) => {
    const bg = slide.querySelector('.scene-bg');
    if (!bg) return;
    const rect = slide.getBoundingClientRect();
    const relative = (rect.top - viewport * 0.5) / viewport;
    bg.style.transform = `translate3d(0, ${relative * -44}px, 0) scale(1.06)`;
  });

  updateProgressFromScroll();
}

function requestScrollTick() {
  if (scrollRaf) return;
  scrollRaf = requestAnimationFrame(updateScrollEffects);
}

function isWorkbookSlideActive() {
  if (!workbookSlide) return false;
  const rect = workbookSlide.getBoundingClientRect();
  const viewport = Math.max(1, slider.clientHeight);
  return rect.top <= viewport * 0.38 && rect.bottom >= viewport * 0.62;
}

function getWorkbookCardStep() {
  if (!workbookRail) return 0;
  const card = workbookRail.querySelector('.dark-card');
  if (!card) return workbookRail.clientWidth * 0.85;
  const railStyle = getComputedStyle(workbookRail);
  const gap = parseFloat(railStyle.columnGap || railStyle.gap || '0') || 0;
  return card.getBoundingClientRect().width + gap;
}

function animateWorkbookRailTo(target) {
  if (!workbookRail) return;

  const maxScroll = Math.max(0, workbookRail.scrollWidth - workbookRail.clientWidth);
  workbookRailTarget = clamp(target, 0, maxScroll);

  if (workbookRailAnimation) {
    cancelAnimationFrame(workbookRailAnimation);
    workbookRailAnimation = null;
  }

  const start = workbookRail.scrollLeft;
  const distance = workbookRailTarget - start;
  if (Math.abs(distance) < 1) return;

  const startedAt = performance.now();
  const duration = 760;
  const easeOutQuart = (t) => 1 - Math.pow(1 - t, 4);

  function tick(now) {
    const progress = clamp((now - startedAt) / duration, 0, 1);
    workbookRail.scrollLeft = start + distance * easeOutQuart(progress);

    if (progress < 1) {
      workbookRailAnimation = requestAnimationFrame(tick);
      return;
    }

    workbookRail.scrollLeft = workbookRailTarget;
    workbookRailAnimation = null;
  }

  workbookRailAnimation = requestAnimationFrame(tick);
}

function holdWorkbookRail(event) {
  if (videoLocked || flashLocked || !workbookRail || !isWorkbookSlideActive() || event.ctrlKey) return;

  const maxScroll = workbookRail.scrollWidth - workbookRail.clientWidth;
  if (maxScroll <= 2) return;

  const horizontalIntent = Math.abs(event.deltaX) > Math.abs(event.deltaY);
  const delta = horizontalIntent ? event.deltaX : event.deltaY;
  if (Math.abs(delta) < 1) return;

  const direction = delta > 0 ? 1 : -1;
  const effectiveLeft = workbookRailAnimation ? workbookRailTarget : workbookRail.scrollLeft;
  const atStart = effectiveLeft <= 2;
  const atEnd = effectiveLeft >= maxScroll - 2;

  if (!horizontalIntent && direction < 0 && atStart) {
    if (workbookRailAnimation) {
      cancelAnimationFrame(workbookRailAnimation);
      workbookRailAnimation = null;
    }
    return;
  }

  if ((direction < 0 && atStart) || (direction > 0 && atEnd)) return;

  if (event.cancelable) event.preventDefault();

  const now = performance.now();
  if (now - lastWorkbookWheelAt < 240) return;
  lastWorkbookWheelAt = now;

  const base = workbookRailAnimation ? workbookRailTarget : workbookRail.scrollLeft;
  animateWorkbookRailTo(base + getWorkbookCardStep() * direction);
}

slider.addEventListener('scroll', handleSliderScroll, { passive: true });
slider.addEventListener('wheel', holdWorkbookRail, { passive: false });
slider.addEventListener('wheel', holdVideoSection, { passive: false });
slider.addEventListener('wheel', holdFlashSection, { passive: false });
slider.addEventListener('touchstart', handleVideoTouchStart, { passive: true });
slider.addEventListener('touchmove', holdVideoTouchMove, { passive: false });
slider.addEventListener('touchmove', holdFlashTouchMove, { passive: false });
window.addEventListener('resize', requestScrollTick);
if (window.visualViewport) {
  window.visualViewport.addEventListener('resize', requestScrollTick);
}

if (scrollSyncVideo) {
  scrollSyncVideo.muted = true;
  scrollSyncVideo.playsInline = true;
  scrollSyncVideo.setAttribute('playsinline', '');
  scrollSyncVideo.setAttribute('webkit-playsinline', '');
  scrollSyncVideo.preload = 'auto';
  scrollSyncVideo.pause();
  scrollSyncVideo.addEventListener('loadedmetadata', () => {
    if (!videoLocked) {
      try { scrollSyncVideo.currentTime = 0.01; } catch (error) {}
    }
    updateVideoTextCue();
    requestScrollTick();
  });
  scrollSyncVideo.addEventListener('loadeddata', updateVideoTextCue);
  scrollSyncVideo.addEventListener('canplay', updateVideoTextCue);
  scrollSyncVideo.addEventListener('seeked', updateVideoTextCue);
  try { scrollSyncVideo.load(); } catch (error) {}
}

document.getElementById('btn-prev').addEventListener('click', () => goTo(currentSlide - 1));
document.getElementById('btn-next').addEventListener('click', () => goTo(currentSlide + 1));

// Nav chapter buttons
document.querySelectorAll('.nav-ch').forEach((b, i) => b.addEventListener('click', () => goTo(i)));

// Hero CTA
document.querySelectorAll('[data-goto]').forEach(b => {
  b.addEventListener('click', () => goTo(parseInt(b.dataset.goto)));
});

// Keyboard
document.addEventListener('keydown', e => {
  if (videoLocked && videoLockKeys.has(e.key)) {
    e.preventDefault();
    const forwardKeys = new Set(['ArrowDown', 'ArrowRight', 'PageDown', 'End', ' ']);
    scrubVideoBy(forwardKeys.has(e.key) ? 1 : -1);
    slider.scrollTop = lockedScrollTop;
    return;
  }

  if (flashLocked && videoLockKeys.has(e.key)) {
    e.preventDefault();
    const forwardKeys = new Set(['ArrowDown', 'ArrowRight', 'PageDown', 'End', ' ']);
    scrubFlashBy(forwardKeys.has(e.key) ? 1 : -1);
    slider.scrollTop = lockedScrollTop;
    return;
  }

  if (e.key === 'ArrowDown' || e.key === 'ArrowRight') goTo(currentSlide + 1);
  if (e.key === 'ArrowUp' || e.key === 'ArrowLeft') goTo(currentSlide - 1);
});

// Question tabs
document.querySelectorAll('.q-tab').forEach(tab => {
  tab.addEventListener('click', () => {
    document.querySelectorAll('.q-tab').forEach(t => t.classList.remove('active'));
    document.querySelectorAll('.q-grid').forEach(g => g.classList.add('hidden'));
    tab.classList.add('active');
    document.getElementById('q-' + tab.dataset.q).classList.remove('hidden');
  });
});

// Emotion tag click
document.querySelectorAll('.em-cloud span').forEach(span => {
  span.addEventListener('click', () => span.classList.toggle('active'));
});

// ── NOISE CANVAS ──
document.querySelectorAll('.noise-canvas').forEach(canvas => {
  const ctx = canvas.getContext('2d');
  let W, H;
  function resize() {
    W = canvas.width = canvas.offsetWidth;
    H = canvas.height = canvas.offsetHeight;
  }
  resize();
  window.addEventListener('resize', resize);
  function drawNoise() {
    if (W < 1 || H < 1) {
      resize();
      requestAnimationFrame(drawNoise);
      return;
    }
    const img = ctx.createImageData(W, H);
    for (let i = 0; i < img.data.length; i += 4) {
      const v = Math.random() * 255;
      img.data[i] = img.data[i+1] = img.data[i+2] = v;
      img.data[i+3] = 255;
    }
    ctx.putImageData(img, 0, 0);
    requestAnimationFrame(drawNoise);
  }
  drawNoise();
});

updateNav();
updateScrollEffects();

// ── VN GAME ──
const CHAR_IMG = null;
    const CHAR_IMGS = {
      neutral: 'data:image/png;base64,',
      smile: 'data:image/png;base64,',
      thinking: 'data:image/png;base64,',
      surprised: 'data:image/png;base64,'
    };

(function(){
    const BGCOLS = { intro:'#0e0e12', memory:'#0d0f18', emotion:'#120e18', value:'#0e1510', deep:'#130f0a', result:'#0e0e12' };
    const CHAR_IMG = null;
    const CHAR_IMGS = {
      neutral: 'data:image/png;base64,',
      smile: 'data:image/png;base64,',
      thinking: 'data:image/png;base64,',
      surprised: 'data:image/png;base64,'
    };
    const POS_EMOTIONS = ['기쁨','만족','희열','즐거움','감동','흐뭇함','번뜩임','고마움','성취감','연대감','따뜻함','편안함','황홀감','몰입감','충만감','전율','짜릿함','놀라움','신남','평온함','활기','열정','재밌음','카타르시스','호기심','희망','경탄','설렘'];
    const NEG_EMOTIONS = ['분노','당황','황당','실망','쓸쓸함','수치심','좌절','무력감','두려움','죄책감','허무함','우울함','무기력함','소외감','괴로움','자괴감','열등감','서운함','답답함'];
    const VALUES = ['사랑','평화','아름다움','균형','창조','관용','자유','정의','평등','조화','감화','연결','연대','용기','헌신','혁신','탐구','탐험','희망','화합','성장','인정','나눔','도전','변화','강인함','유연함','온전함','정교함','통찰','창의성','독창성'];
    const CHAPTERS = ['경험 성찰','경험 선택','감정 탐색','가치 발견','성찰 완성','나의 문장'];
    const GAME_CHAR_IMGS = {
      neutral: 'vn-character-smile.png',
      smile: 'vn-character-smile.png',
      thinking: 'vn-character-thinking.png',
      surprised: 'vn-character-thinking.png'
    };

    let st = { expType:null, expText:'', situation:'', emotion:'', value:'', chapter:0 };
    let typeTimer = null;

    const $ = id => document.getElementById(id);
    const bg = () => $('vn-scene-bg');
    const art = () => $('vn-scene-art');
    const vnWrap = () => $('vn-wrap');
    const dialogue = () => $('vn-dialogue');
    const speaker = () => $('vn-speaker');
    const textEl = () => $('vn-text');
    const cursor = () => $('vn-cursor');
    const contBtn = () => $('vn-continue');
    const choices = () => $('vn-choices');
    const inputArea = () => $('vn-input-area');
    const inputEl = () => $('vn-input');
    const submitBtn = () => $('vn-submit');
    const resultEl = () => $('vn-result');
    const progEl = () => $('vn-progress');
    const chapterEl = () => $('vn-chapter');

    function setBg(key) { bg().style.background = BGCOLS[key] || '#0e0e12'; }
    function setArt(key) {
      const imgMap = { intro:'neutral', memory:'neutral', emotion:'thinking', value:'thinking', deep:'thinking', result:'smile' };
      const charKey = key in GAME_CHAR_IMGS ? key : (imgMap[key] || 'neutral');
      const src = GAME_CHAR_IMGS[charKey];
      art().style.opacity = '0';
      setTimeout(() => {
        art().innerHTML = src ? `<img src="${src}" style="height:100%; max-height:380px; width:auto; object-fit:contain; object-position:bottom center; filter:drop-shadow(0 0 24px rgba(100,160,255,0.3));">` : '';
        art().style.opacity = '1';
      }, 300);
    }
    function setProgress(n) {
      st.chapter = n;
      chapterEl().textContent = CHAPTERS[n] || '경험 성찰';
      const html = Array.from({length:5},(_,i) => {
        const cls = i < n ? 'done' : i === n ? 'active' : '';
        const w = i === n ? '18px' : '6px';
        const bg2 = i < n ? '#c9a96e' : i === n ? '#e8e0cc' : 'rgba(255,255,255,0.15)';
        return `<div style="width:${w};height:6px;border-radius:3px;background:${bg2};transition:all 0.3s;"></div>`;
      }).join('');
      progEl().innerHTML = html;
    }
    function type(text, cb) {
      if(typeTimer) clearInterval(typeTimer);
      textEl().textContent = '';
      cursor().style.display = 'inline-block';
      let i = 0;
      typeTimer = setInterval(() => {
        if(i < text.length) { textEl().textContent += text[i++]; }
        else { clearInterval(typeTimer); typeTimer = null; if(cb) cb(); }
      }, 7);
    }
    function speak(spk, text, cb) {
      speaker().textContent = spk || '';
      setContinueVisible(false);
      clearChoices(); hideInput();
      type(text, () => {
        if(cb) {
          setContinueVisible(true);
          contBtn().onclick = () => { setContinueVisible(false); cb(); };
        }
      });
    }
    function setDialogueMode(mode) {
      const box = dialogue();
      const wrap = vnWrap();
      box.classList.remove('choice-active', 'picker-active', 'input-active', 'result-active');
      wrap.classList.remove('choice-active', 'picker-active', 'input-active', 'result-active');
      if (mode) box.classList.add(mode);
      if (mode) wrap.classList.add(mode);
    }
    function clearChoices() {
      choices().innerHTML = '';
      setDialogueMode('');
    }
    function hideInput() { inputArea().style.display = 'none'; }
    function setContinueVisible(visible) {
      const btn = contBtn();
      btn.style.visibility = visible ? 'visible' : 'hidden';
      btn.style.opacity = visible ? '1' : '0';
      btn.style.pointerEvents = visible ? 'auto' : 'none';
    }
    function showChoices(list) {
      choices().innerHTML = '';
      setDialogueMode('choice-active');
      list.forEach(c => {
        const btn = document.createElement('button');
        btn.className = 'vn-choice-btn';
        btn.innerHTML = c.tag ? `<span class="vn-tag">${c.tag}</span>${c.text}` : c.text;
        btn.onclick = c.action;
        choices().appendChild(btn);
      });
    }
    function showInput(ph, cb) {
      inputEl().value = '';
      inputEl().placeholder = ph || '자유롭게 적어보세요...';
      inputArea().style.display = 'flex';
      setDialogueMode('input-active');
      submitBtn().onclick = () => {
        const v = inputEl().value.trim();
        if(v) { hideInput(); cb(v); }
        else { inputEl().style.borderColor='rgba(200,100,100,0.4)'; setTimeout(()=>inputEl().style.borderColor='',600); }
      };
    }
    function showEmoPicker(group, cb) {
      const list = group === 'positive' ? POS_EMOTIONS : NEG_EMOTIONS;
      choices().innerHTML = '';
      setDialogueMode('picker-active');
      const wrap = document.createElement('div');
      wrap.style.cssText = 'display:flex;flex-wrap:wrap;gap:7px;padding:0 0 4px;';
      let sel = null;
      list.forEach(em => {
        const b = document.createElement('button');
        b.className = 'vn-pill'; b.textContent = em;
        b.onclick = () => {
          if(sel) sel.classList.remove('sel-em');
          sel = b; b.classList.add('sel-em');
          cb(em);
        };
        wrap.appendChild(b);
      });
      choices().appendChild(wrap);
    }
    function showValPicker(cb) {
      choices().innerHTML = '';
      setDialogueMode('picker-active');
      const wrap = document.createElement('div');
      wrap.style.cssText = 'display:flex;flex-wrap:wrap;gap:7px;padding:0 0 4px;';
      let sel = null;
      VALUES.forEach(v => {
        const b = document.createElement('button');
        b.className = 'vn-pill'; b.textContent = v;
        b.style.fontFamily = "'Noto Serif KR',serif";
        b.onclick = () => {
          if(sel) sel.classList.remove('sel-val');
          sel = b; b.classList.add('sel-val');
          cb(v);
        };
        wrap.appendChild(b);
      });
      choices().appendChild(wrap);
    }
    function showResult() {
      const sentence = `나는 ${st.situation || st.expText.slice(0,12)}이(가) 주는 ${st.value}에 ${st.emotion}을 느끼며 살아가겠다.`;
      setDialogueMode('result-active');
      resultEl().style.display = 'block';
      resultEl().innerHTML = `
        <div class="vn-result-card"><div class="vn-result-label">경험</div><div class="vn-result-value">${st.expText}</div></div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:10px;">
          <div class="vn-result-card"><div class="vn-result-label">감정</div><div class="vn-result-value">${st.emotion}</div></div>
          <div class="vn-result-card"><div class="vn-result-label">가치</div><div class="vn-result-value">${st.value}</div></div>
        </div>
        <div class="vn-final-sentence">${sentence}</div>
        <button onclick="vnCopy('${sentence.replace(/'/g,"\\'")}','this')" style="background:transparent;border:0.5px solid rgba(255,255,255,0.15);border-radius:8px;padding:9px 18px;color:rgba(255,255,255,0.45);font-family:'Noto Sans KR',sans-serif;font-size:13px;cursor:pointer;margin-right:8px;margin-top:4px;">문장 복사하기</button>
        <button onclick="vnRestart()" style="background:transparent;border:0.5px solid rgba(255,255,255,0.15);border-radius:8px;padding:9px 18px;color:rgba(255,255,255,0.45);font-family:'Noto Sans KR',sans-serif;font-size:13px;cursor:pointer;margin-top:4px;">처음부터 다시</button>
      `;
    }

    window.vnCopy = function(text, el) {
      navigator.clipboard.writeText(text).then(() => { if(el) {}; alert('복사되었습니다!'); });
    };
    window.vnRestart = function() {
      resultEl().style.display = 'none'; resultEl().innerHTML = '';
      st = { expType:null, expText:'', situation:'', emotion:'', value:'', chapter:0 };
      startVN();
    };

    function startVN() {
      setBg('intro'); setArt('neutral'); setProgress(0);
      clearChoices(); hideInput();
      resultEl().style.display = 'none';
      resultEl().innerHTML = '';
      speak('', '...어서 와. 여기는 네가 겪어온 경험들이 조용히 기다리는 곳이야.', () => {
        speak('', '우리는 그 경험 하나를 함께 들여다볼 거야. 천천히, 깊게.', () => {
          setProgress(1); setBg('memory');
          speak('안내자', '어떤 종류의 경험을 성찰하고 싶어?', () => {
            showChoices([
              { tag:'긍정', text:'기쁘거나 설레거나 뿌듯했던 경험', action:()=>{ st.expType='positive'; setArt('neutral'); chooseExp(); }},
              { tag:'부정', text:'답답하거나 힘들었던 경험', action:()=>{ st.expType='negative'; setArt('thinking'); chooseExp(); }},
              { tag:'중립', text:'평범했는데 왠지 기억에 남는 경험', action:()=>{ st.expType='neutral'; setArt('thinking'); chooseExp(); }}
            ]);
          });
        });
      });
    }

    function chooseExp() {
      clearChoices();
      const p = { positive:'설레서 잠이 안 잤던 밤, 뭔가 해냈을 때의 뿌듯함, 사람이나 장소가 좋았던 순간... 하나만 떠올려봐.', negative:'화가 났던 순간, 실망했던 기억, 허무했던 경험... 감정적으로 반응하지 말고 그냥 들여다보자.', neutral:'특별할 것 없었는데 자꾸 생각나는 경험이 있어? 그게 뭔지 적어봐.' };
      speak('안내자', p[st.expType], () => {
        showInput('그 경험을 간단히 적어봐...', val => { st.expText = val; exploreEmotion(); });
      });
    }

    function exploreEmotion() {
      setProgress(2); setBg('emotion'); setArt('thinking');
      speak('안내자', `"${st.expText.slice(0,30)}${st.expText.length>30?'...':''}"`, () => {
        speak('안내자', '그 경험을 떠올렸을 때 — 어떤 감정이 가장 먼저 올라와?', () => {
          showEmoPicker(st.expType === 'positive' ? 'positive' : 'negative', em => {
            st.emotion = em;
            setTimeout(confirmEmotion, 400);
          });
        });
      });
    }

    function confirmEmotion() {
      clearChoices();
      setArt('surprised');
      speak('안내자', `${st.emotion}... 그렇구나.`, () => {
        speak('안내자', '그 감정이 가장 강하게 느껴진 순간은 어떤 상황에서였어?', () => {
          showInput('그 순간을 짧게 묘사해봐...', val => { st.situation = val; exploreValue(); });
        });
      });
    }

    function exploreValue() {
      setProgress(3); setBg('value'); setArt('thinking');
      speak('안내자', '이제 조금 더 깊이 들어가볼게.', () => {
        speak('안내자', `왜 그 순간에 ${st.emotion}을 느꼈을까? 그 경험이 너에게 뭔가를 건드린 거야.`, () => {
          speak('안내자', '아래 가치들 중에서 — 그 경험이 건드린 것과 가장 가까운 걸 골라봐.', () => {
            showValPicker(v => { st.value = v; setTimeout(buildSentence, 400); });
          });
        });
      });
    }

    function buildSentence() {
      clearChoices(); setProgress(4); setBg('result'); setArt('smile');
      speak('안내자', `${st.value}... 그게 너한테 중요한 거구나.`, () => {
        speak('안내자', '이제 성찰한 걸 한 문장으로 만들어볼게.', () => {
          speak('안내자', '이 문장은 완벽하지 않아도 돼. 살아가면서 계속 다듬어지는 문장이거든.', () => {
            setProgress(5);
            showResult();
            setDialogueMode('result-active');
            setContinueVisible(false);
          });
        });
      });
    }

    // Particles
    (function(){
      const c = $('vn-particle-canvas');
      if(!c) return;
      const ctx = c.getContext('2d');
      let W, H, pts = [];
      function resize(){
        const r = $('vn-root');
        if(!r) return;
        W = c.width = r.offsetWidth; H = c.height = r.offsetHeight;
      }
      function mkPt(){ return {x:Math.random()*W||200, y:(H||400)+5, vx:(Math.random()-0.5)*0.3, vy:-(Math.random()*0.4+0.15), sz:Math.random()*1.5+0.3, al:Math.random()*0.2+0.05, life:0, max:Math.random()*400+200}; }
      resize();
      for(let i=0;i<25;i++){const p=mkPt();p.y=Math.random()*(H||400);p.life=Math.random()*p.max;pts.push(p);}
      function draw(){
        ctx.clearRect(0,0,W,H);
        if(pts.length<30 && Math.random()<0.12) pts.push(mkPt());
        pts = pts.filter(p=>{
          p.x+=p.vx; p.y+=p.vy; p.life++;
          const a = p.life<p.max*0.2?(p.life/(p.max*0.2))*p.al : p.life>p.max*0.8?((p.max-p.life)/(p.max*0.2))*p.al : p.al;
          ctx.beginPath(); ctx.arc(p.x,p.y,p.sz,0,Math.PI*2);
          ctx.fillStyle=`rgba(201,169,110,${Math.max(0,a).toFixed(3)})`; ctx.fill();
          return p.life<p.max;
        });
        requestAnimationFrame(draw);
      }
      draw();
      window.addEventListener('resize', resize);
    })();

    startVN();
  })();
